    public func spawn(program: String, argv: [String]? = nil, envp: [String]? = nil, env: [String: String]? = nil, cwd: String? = nil, stdio: Stdio? = nil) async throws -> UInt {
        return try await fridaAsync(UInt.self) { op in
            let options = frida_spawn_options_new()!
            let (rawArgv, rawArgvLength) = Marshal.strvFromArray(argv)
            if let rawArgv = rawArgv {
                frida_spawn_options_set_argv(options, rawArgv, rawArgvLength)
                g_strfreev(rawArgv)
            }
            let (rawEnvp, rawEnvpLength) = Marshal.strvFromArray(envp)
            if let rawEnvp = rawEnvp {
                frida_spawn_options_set_envp(options, rawEnvp, rawEnvpLength)
                g_strfreev(rawEnvp)
            }
            let (rawEnv, rawEnvLength) = Marshal.envpFromDictionary(env)
            if let rawEnv = rawEnv {
                frida_spawn_options_set_env(options, rawEnv, rawEnvLength)
                g_strfreev(rawEnv)
            }
            if let cwd = cwd {
                frida_spawn_options_set_cwd(options, cwd)
            }
            if let stdio = stdio {
                frida_spawn_options_set_stdio(options, FridaStdio(numericCast(stdio.rawValue)))
            }
            frida_device_spawn(self.handle, program, options, op.cancellable, { sourcePtr, asyncResultPtr, userData in
                let op = InternalOp<UInt>.takeRetained(from: userData!)

                var rawError: UnsafeMutablePointer<GError>? = nil
                let rawResult = frida_device_spawn_finish(OpaquePointer(sourcePtr), asyncResultPtr, &rawError)

                if let rawError {
                    op.resumeFailure(Marshal.takeNativeError(rawError))
                    return
                }

                op.resumeSuccess(UInt(rawResult))
            }, op.userData)
            g_object_unref(gpointer(options))
        }
    }

