    private let onProcessCrashed: @convention(c) (OpaquePointer, OpaquePointer, gpointer) -> Void = { _, arg0, userData in
        let connection = Unmanaged<SignalConnection<Device>>.fromOpaque(userData).takeUnretainedValue()
        guard let instance = connection.instance else { return }
        g_object_ref(gpointer(arg0))
        let crashValue = CrashDetails(handle: arg0)
        instance.publish(.processCrashed(crashValue))
    }

    private let onOutput: @convention(c) (OpaquePointer, guint, gint, OpaquePointer, gpointer) -> Void = { _, arg0, arg1, arg2, userData in
        let connection = Unmanaged<SignalConnection<Device>>.fromOpaque(userData).takeUnretainedValue()
        guard let instance = connection.instance else { return }
        let dataValue = Marshal.arrayFromBytes(arg2)!
        instance.publish(.output(data: dataValue, fd: Int(arg1), pid: UInt(arg0)))
    }

    private let onUninjected: @convention(c) (OpaquePointer, guint, gpointer) -> Void = { _, arg0, userData in
        let connection = Unmanaged<SignalConnection<Device>>.fromOpaque(userData).takeUnretainedValue()
        guard let instance = connection.instance else { return }
        instance.publish(.uninjected(UInt(arg0)))
    }

    private let onLost: @convention(c) (OpaquePointer, gpointer) -> Void = { _, userData in
        let connection = Unmanaged<SignalConnection<Device>>.fromOpaque(userData).takeUnretainedValue()
        guard let instance = connection.instance else { return }
        instance.eventSource.finish(replayLast: .lost)
    }

    private func publish(_ event: Event) {
        eventSource.yield(event)
    }

    public var description: String {
        return "Frida.Device(isLost: \(isLost), id: \"\(id)\", name: \"\(name)\", type: \(type))"
    }

    public var icon: Icon? {
        guard let variant = frida_device_get_icon(handle) else {
            return nil
        }
        let dict = Marshal.valueFromVariant(variant) as! [String: Any]
        return Marshal.iconFromVarDict(dict)
    }

    public static func == (lhs: Device, rhs: Device) -> Bool {
        return lhs.handle == rhs.handle
    }

    public func hash(into hasher: inout Hasher) {
        hasher.combine(UInt(bitPattern: handle))
    }
}

