open class AuthenticationService {
    public let handle: OpaquePointer

    public init() {
        Runtime.ensureInitialized()
        handle = AuthenticationService.makeInstance()
        AuthenticationService.register(self, on: handle)
    }

    deinit {
        g_object_unref(gpointer(handle))
    }

    open func authenticate(token: String) async throws -> String {
        fatalError("Override authenticate in your AuthenticationService subclass")
    }

    private static let quark: GQuark = "frida-swift-authentication-service".withCString { g_quark_from_string($0) }

    private static let gType: GType = registerType()

    private static func registerType() -> GType {
        var info = GTypeInfo(
            class_size: guint16(MemoryLayout<GObjectClass>.stride),
            base_init: nil,
            base_finalize: nil,
            class_init: { _, _ in },
            class_finalize: nil,
            class_data: nil,
            instance_size: guint16(MemoryLayout<GObject>.stride),
            n_preallocs: 0,
            instance_init: { _, _ in },
            value_table: nil
        )
        let type: GType = "FridaSwiftAuthenticationService".withCString { cStr in
            g_type_register_static(g_type_from_name("GObject"), cStr, &info, GTypeFlags(rawValue: 0))
        }
        var ifaceInfo = GInterfaceInfo(
            interface_init: { ifacePtr, _ in
                let iface = ifacePtr!.assumingMemoryBound(to: FridaAuthenticationServiceIface.self)
                iface.pointee.authenticate = AuthenticationService.authenticateThunk
                iface.pointee.authenticate_finish = AuthenticationService.authenticateFinishThunk
            },
            interface_finalize: nil,
            interface_data: nil
        )
        g_type_add_interface_static(type, frida_authentication_service_get_type(), &ifaceInfo)
        return type
    }

    private static func makeInstance() -> OpaquePointer {
        guard let raw = g_object_new_with_properties(gType, 0, nil, nil) else {
            fatalError("Failed to create FridaSwiftAuthenticationService")
        }
        return OpaquePointer(raw)
    }

    private static func register(_ instance: AuthenticationService, on handle: OpaquePointer) {
        let gobj = UnsafeMutableRawPointer(handle).assumingMemoryBound(to: GObject.self)
        g_object_set_qdata_full(gobj, quark, Unmanaged.passRetained(Box(instance)).toOpaque(), { data in
            if let data {
                Unmanaged<Box>.fromOpaque(data).release()
            }
        })
    }

    private static func getBox(from ptr: OpaquePointer) -> Box {
        let gobj = UnsafeMutableRawPointer(ptr).assumingMemoryBound(to: GObject.self)
        return Unmanaged<Box>.fromOpaque(g_object_get_qdata(gobj, quark)!).takeUnretainedValue()
    }

    private static func makeError(from error: Swift.Error) -> UnsafeMutablePointer<GError>? {
        String(describing: error).withCString { cStr in
            g_error_new_literal(frida_error_quark(), gint(FRIDA_ERROR_INVALID_OPERATION.rawValue), cStr)
        }
    }

    private static let authenticateThunk: @convention(c) (
        OpaquePointer?,
        UnsafePointer<CChar>?,
        UnsafeMutablePointer<GCancellable>?,
        GAsyncReadyCallback?,
        gpointer?
    ) -> Void = { selfPtr, rawValue, cancellable, callback, userData in
        let box = AuthenticationService.getBox(from: selfPtr!)
        let value = rawValue.map { String(cString: $0) } ?? ""
        guard let task = g_task_new(UnsafeMutableRawPointer(selfPtr), cancellable, callback, userData) else {
            return
        }
        Task.detached {
            do {
                let result = try await box.instance.authenticate(token: value)
                result.withCString { cStr in
                    g_task_return_pointer(task, UnsafeMutableRawPointer(g_strdup(cStr)), { ptr in if let ptr { g_free(ptr) } })
                }
            } catch {
                g_task_return_error(task, AuthenticationService.makeError(from: error))
            }
            g_object_unref(gpointer(task))
        }
    }

    private static let authenticateFinishThunk: @convention(c) (
        OpaquePointer?,
        OpaquePointer?,
        UnsafeMutablePointer<UnsafeMutablePointer<GError>?>?
    ) -> UnsafeMutablePointer<CChar>? = { _, resultPtr, errorOut in
        return g_task_propagate_pointer(resultPtr, errorOut)?.assumingMemoryBound(to: CChar.self)
    }

    private final class Box {
        let instance: AuthenticationService
        init(_ instance: AuthenticationService) {
            self.instance = instance
        }
    }
}

