        Task.detached {
            do {
                let result = try await box.instance.handleRequest(request: value)
                if let result {
                    g_object_ref(gpointer(result.handle))
                    g_task_return_pointer(task, UnsafeMutableRawPointer(result.handle), { ptr in if let ptr { g_object_unref(ptr) } })
